22→@RestController
23→@RequestMapping("/api/auth")
24→public class AuthController {
25→
26→    private final AuthService authService;
27→
28→    public AuthController(AuthService authService) {
29→        this.authService = authService;
30→    }
31→
32→    @PostMapping("/register")
33→    public ResponseEntity<Map<String, Object>> register(@Valid @RequestBody RegisterRequest request) {
34→        Map<String, Object> result = authService.register(request);
35→        return ResponseEntity.status(HttpStatus.CREATED).body(result);
36→    }
37→
38→    @PostMapping("/login")
39→    public ResponseEntity<LoginResponse> login(@Valid @RequestBody LoginRequest request) {
40→        LoginResponse result = authService.login(request);
41→        return ResponseEntity.ok(result);
42→    }
43→
44→    @GetMapping("/me")
45→    public ResponseEntity<?> me() {
46→        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
47→        if (authentication == null || !(authentication.getPrincipal() instanceof Long)) {
48→            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
49→                    .body(Map.of("message", "Unauthorized"));
50→        }
51→        Long userId = (Long) authentication.getPrincipal();
52→        Map<String, Object> result = authService.getCurrentUser(userId);
53→        return ResponseEntity.ok(result);
54→    }
55→
56→    @ExceptionHandler(AuthService.DuplicateUsernameException.class)
57→    public ResponseEntity<Map<String, String>> handleDuplicateUsername(AuthService.DuplicateUsernameException ex) {
58→        return ResponseEntity.status(HttpStatus.CONFLICT)
59→                .body(Map.of("message", ex.getMessage()));
60→    }
61→
62→    @ExceptionHandler(AuthService.BadCredentialsException.class)
63→    public ResponseEntity<Map<String, String>> handleBadCredentials(AuthService.BadCredentialsException ex) {
64→        return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
65→                .body(Map.of("message", ex.getMessage()));
